"""
Advanced Complexity Analysis and Resource Allocation System
Analyzes input complexity and determines optimal resource allocation for processing
"""
import re
import math
from dataclasses import dataclass
from typing import Dict, List, Any, Optional, Tuple
from enum import Enum

from .runtime_profiles import resource_manager, ResourceProfile

class ComplexityType(Enum):
    """Types of complexity detected in input"""
    SIMPLE = "simple"
    STRUCTURED = "structured"
    ANALYTICAL = "analytical"
    RESEARCH = "research"
    TECHNICAL = "technical"
    CREATIVE = "creative"
    MULTI_STEP = "multi_step"

class ResourceRequirement(Enum):
    """Resource requirement levels"""
    MINIMAL = "minimal"      # 1-15%
    LOW = "low"             # 16-35%
    MODERATE = "moderate"   # 36-55%
    HIGH = "high"           # 56-75%
    CRITICAL = "critical"   # 75%+ (special handling)

@dataclass
class ComplexityScore:
    """Result of complexity analysis"""
    total_score: float          # 0.0 - 1.0
    complexity_types: List[ComplexityType]
    resource_requirement: ResourceRequirement
    recommended_percentage: int
    estimated_time_multiplier: float
    reasoning: str
    factors: Dict[str, float]   # Individual factor scores

class ComplexityAnalyzer:
    """
    Analyzes input complexity and recommends resource allocation
    """

    def __init__(self):
        self.technical_terms = {
            # Programming concepts
            'algorithm', 'recursion', 'optimization', 'complexity', 'refactoring',
            'architecture', 'design pattern', 'async', 'concurrent', 'parallel',
            'machine learning', 'ai', 'neural network', 'api', 'database',
            'blockchain', 'cryptography', 'security', 'performance', 'scalability',

            # Research indicators
            'analyze', 'research', 'investigate', 'study', 'examine', 'evaluate',
            'compare', 'contrast', 'synthesize', 'methodology', 'hypothesis',
            'literature review', 'meta-analysis', 'systematic review',

            # Scientific terms
            'quantum', 'molecular', 'genetic', 'statistical', 'mathematical',
            'theoretical', 'empirical', 'experimental', 'correlation', 'causation',

            # Business/analytical
            'market analysis', 'financial modeling', 'risk assessment', 'strategy',
            'optimization', 'forecasting', 'trend analysis', 'competitive analysis'
        }

        self.research_indicators = [
            # Research trigger words
            r'research\s+(?:about|on|into)',
            r'find\s+(?:information|sources|papers|studies)',
            r'comprehensive\s+(?:analysis|review|study)',
            r'literature\s+review',
            r'meta[\-\s]analysis',
            r'systematic\s+review',
            r'compare\s+and\s+contrast',
            r'pros\s+and\s+cons',
            r'advantages\s+and\s+disadvantages',
            r'what\s+are\s+the\s+(?:causes|effects|implications)',
            r'explain\s+(?:why|how).*(?:works?|happens?)',
            r'root\s+cause\s+analysis',
            r'deep\s+dive',
            r'thorough\s+(?:analysis|examination|investigation)',
            r'multiple\s+(?:perspectives|viewpoints|approaches)',
            r'current\s+(?:state|trends|developments)',
            r'latest\s+(?:research|findings|advances)'
        ]

        self.multi_step_indicators = [
            r'step\s+by\s+step',
            r'walkthrough',
            r'guide\s+me\s+through',
            r'process\s+for',
            r'how\s+to\s+(?:create|build|implement|develop)',
            r'tutorial',
            r'implementation\s+plan',
            r'roadmap',
            r'methodology',
            r'framework',
            r'approach\s+to',
            r'strategy\s+for'
        ]

        self.creative_indicators = [
            r'creative\s+(?:writing|ideas|solutions)',
            r'brainstorm',
            r'innovative\s+(?:approaches|solutions)',
            r'think\s+outside\s+the\s+box',
            r'novel\s+(?:ideas|approaches)',
            r'unique\s+(?:perspective|solution)',
            r'artistic\s+(?:vision|concept)',
            r'design\s+(?:concept|vision)',
            r'storytelling',
            r'narrative'
        ]

    def analyze_complexity(self, user_input: str, context: str = "") -> ComplexityScore:
        """
        Analyze input complexity and recommend resource allocation
        """
        factors = {}
        complexity_types = []

        # Factor 1: Input length and structure (0.0 - 0.2)
        length_score = self._analyze_length(user_input)
        factors['length'] = length_score

        # Factor 2: Technical terminology density (0.0 - 0.25)
        technical_score = self._analyze_technical_content(user_input)
        factors['technical'] = technical_score

        # Factor 3: Research requirements (0.0 - 0.3)
        research_score = self._analyze_research_requirements(user_input)
        factors['research'] = research_score
        if research_score > 0.3:
            complexity_types.append(ComplexityType.RESEARCH)

        # Factor 4: Multi-step reasoning (0.0 - 0.25)
        reasoning_score = self._analyze_reasoning_requirements(user_input)
        factors['reasoning'] = reasoning_score
        if reasoning_score > 0.4:
            complexity_types.append(ComplexityType.MULTI_STEP)

        # Factor 5: Creative requirements (0.0 - 0.2)
        creative_score = self._analyze_creative_requirements(user_input)
        factors['creative'] = creative_score
        if creative_score > 0.3:
            complexity_types.append(ComplexityType.CREATIVE)

        # Factor 6: Analytical depth (0.0 - 0.25)
        analytical_score = self._analyze_analytical_requirements(user_input)
        factors['analytical'] = analytical_score
        if analytical_score > 0.4:
            complexity_types.append(ComplexityType.ANALYTICAL)

        # Factor 7: Context complexity (0.0 - 0.15)
        context_score = self._analyze_context_complexity(context)
        factors['context'] = context_score

        # Calculate total complexity score
        total_score = sum(factors.values())
        total_score = min(1.0, total_score)  # Cap at 1.0

        # Determine complexity types
        if total_score < 0.2:
            complexity_types.append(ComplexityType.SIMPLE)
        elif 'list' in user_input.lower() or 'give me' in user_input.lower():
            complexity_types.append(ComplexityType.STRUCTURED)
        elif technical_score > 0.3:
            complexity_types.append(ComplexityType.TECHNICAL)

        # Map complexity to resource requirements
        resource_req, recommended_percentage = self._map_complexity_to_resources(total_score, complexity_types)

        # Calculate time multiplier
        time_multiplier = 1.0 + (total_score * 2.0)  # 1.0x to 3.0x

        # Generate reasoning
        reasoning = self._generate_reasoning(factors, complexity_types, total_score)

        return ComplexityScore(
            total_score=total_score,
            complexity_types=complexity_types,
            resource_requirement=resource_req,
            recommended_percentage=recommended_percentage,
            estimated_time_multiplier=time_multiplier,
            reasoning=reasoning,
            factors=factors
        )

    def _analyze_length(self, text: str) -> float:
        """Analyze complexity based on input length"""
        word_count = len(text.split())
        sentence_count = len([s for s in text.split('.') if s.strip()])

        # Base score on word count
        if word_count < 10:
            return 0.05
        elif word_count < 25:
            return 0.1
        elif word_count < 50:
            return 0.15
        else:
            return 0.2

    def _analyze_technical_content(self, text: str) -> float:
        """Analyze technical terminology density"""
        words = text.lower().split()
        technical_matches = sum(1 for word in words if any(term in word for term in self.technical_terms))

        if not words:
            return 0.0

        density = technical_matches / len(words)
        return min(0.25, density * 2)  # Scale to 0.25 max

    def _analyze_research_requirements(self, text: str) -> float:
        """Analyze if input requires research"""
        text_lower = text.lower()
        research_matches = 0

        for pattern in self.research_indicators:
            if re.search(pattern, text_lower):
                research_matches += 1

        # Strong research indicators
        if any(phrase in text_lower for phrase in [
            'research', 'comprehensive analysis', 'literature review',
            'find information', 'latest developments', 'current state'
        ]):
            research_matches += 2

        return min(0.3, research_matches * 0.1)

    def _analyze_reasoning_requirements(self, text: str) -> float:
        """Analyze multi-step reasoning requirements"""
        text_lower = text.lower()
        reasoning_score = 0.0

        # Multi-step indicators
        for pattern in self.multi_step_indicators:
            if re.search(pattern, text_lower):
                reasoning_score += 0.1

        # Reasoning keywords
        reasoning_words = ['explain', 'analyze', 'compare', 'evaluate', 'synthesize', 'why', 'how']
        for word in reasoning_words:
            if word in text_lower:
                reasoning_score += 0.05

        return min(0.25, reasoning_score)

    def _analyze_creative_requirements(self, text: str) -> float:
        """Analyze creative thinking requirements"""
        text_lower = text.lower()
        creative_score = 0.0

        for pattern in self.creative_indicators:
            if re.search(pattern, text_lower):
                creative_score += 0.1

        return min(0.2, creative_score)

    def _analyze_analytical_requirements(self, text: str) -> float:
        """Analyze analytical depth requirements"""
        text_lower = text.lower()
        analytical_score = 0.0

        analytical_words = [
            'analyze', 'analysis', 'break down', 'examine', 'investigate',
            'root cause', 'deep dive', 'thorough', 'comprehensive', 'detailed'
        ]

        for word in analytical_words:
            if word in text_lower:
                analytical_score += 0.05

        # Complex question patterns
        if any(phrase in text_lower for phrase in [
            'what are the implications', 'how does this affect',
            'what are the consequences', 'impact analysis'
        ]):
            analytical_score += 0.1

        return min(0.25, analytical_score)

    def _analyze_context_complexity(self, context: str) -> float:
        """Analyze context complexity"""
        if not context:
            return 0.0

        context_length = len(context.split())
        if context_length < 50:
            return 0.05
        elif context_length < 200:
            return 0.1
        else:
            return 0.15

    def _map_complexity_to_resources(self, total_score: float, complexity_types: List[ComplexityType]) -> Tuple[ResourceRequirement, int]:
        """Map complexity score to resource requirements"""

        # Base mapping
        if total_score <= 0.15:
            base_req = ResourceRequirement.MINIMAL
            base_percentage = max(1, int(total_score * 100))  # 1-15%
        elif total_score <= 0.35:
            base_req = ResourceRequirement.LOW
            base_percentage = 16 + int((total_score - 0.15) * 95)  # 16-35%
        elif total_score <= 0.55:
            base_req = ResourceRequirement.MODERATE
            base_percentage = 36 + int((total_score - 0.35) * 95)  # 36-55%
        elif total_score <= 0.75:
            base_req = ResourceRequirement.HIGH
            base_percentage = 56 + int((total_score - 0.55) * 95)  # 56-75%
        else:
            base_req = ResourceRequirement.CRITICAL
            base_percentage = 75  # Cap at 75%

        # Adjust based on complexity types
        if ComplexityType.RESEARCH in complexity_types:
            base_percentage = min(75, base_percentage + 10)
        if ComplexityType.MULTI_STEP in complexity_types:
            base_percentage = min(75, base_percentage + 5)
        if ComplexityType.ANALYTICAL in complexity_types:
            base_percentage = min(75, base_percentage + 8)

        # Check hardware feasibility
        try:
            test_profile = resource_manager.get_profile_by_percentage(base_percentage)
            feasible, _ = resource_manager.is_profile_feasible(test_profile)

            if not feasible:
                # Reduce to feasible level
                for test_pct in range(base_percentage - 1, 0, -1):
                    test_profile = resource_manager.get_profile_by_percentage(test_pct)
                    feasible, _ = resource_manager.is_profile_feasible(test_profile)
                    if feasible:
                        base_percentage = test_pct
                        break
        except:
            # Fallback to safe percentage
            base_percentage = min(25, base_percentage)

        return base_req, base_percentage

    def _generate_reasoning(self, factors: Dict[str, float], complexity_types: List[ComplexityType], total_score: float) -> str:
        """Generate human-readable reasoning for the complexity assessment"""

        reasoning_parts = []

        # Primary complexity drivers
        high_factors = [(k, v) for k, v in factors.items() if v > 0.2]
        if high_factors:
            reasoning_parts.append(f"High complexity factors: {', '.join([f'{k} ({v:.2f})' for k, v in high_factors])}")

        # Complexity types
        if complexity_types:
            type_names = [t.value.replace('_', ' ') for t in complexity_types]
            reasoning_parts.append(f"Detected complexity types: {', '.join(type_names)}")

        # Overall assessment
        if total_score < 0.2:
            reasoning_parts.append("Simple query requiring minimal resources")
        elif total_score < 0.4:
            reasoning_parts.append("Moderate complexity requiring balanced resources")
        elif total_score < 0.6:
            reasoning_parts.append("Complex query requiring substantial resources")
        else:
            reasoning_parts.append("Highly complex query requiring maximum available resources")

        return ". ".join(reasoning_parts) + "."

# Global instance
complexity_analyzer = ComplexityAnalyzer()